import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { apiClient } from "@/App";
import { toast } from "sonner";
import { Plus } from "lucide-react";

const StaffPage = () => {
  const [staff, setStaff] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    full_name: "",
    email: "",
    phone: "",
    employee_number: "",
    department: "",
    position: "",
    role: "teacher",
    password: "",
    salary: "",
    joined_date: ""
  });

  useEffect(() => {
    fetchStaff();
  }, []);

  const fetchStaff = async () => {
    try {
      setLoading(true);

      const response = await apiClient.get("/staff");

      // 🔥 FIX: correct backend structure
      const staffData = response?.data?.data;

      // 🔥 SAFETY: ensure array always
      setStaff(Array.isArray(staffData) ? staffData : []);

    } catch (error) {
      toast.error("Failed to fetch staff");
      setStaff([]); // prevent map crash
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/staff", formData);

      toast.success("Staff member added successfully");

      setDialogOpen(false);

      fetchStaff();

    } catch (error) {
      toast.error(error.response?.data?.detail || "Failed to add staff");
    }
  };

  // 🔥 SAFETY FALLBACK (prevents crash if API breaks again)
  const safeStaff = Array.isArray(staff) ? staff : [];

  return (
    <div className="space-y-6">

      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-slate-900">Staff Management</h2>
          <p className="text-slate-600 mt-1">Manage staff members and roles</p>
        </div>

        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button data-testid="add-staff-btn">
              <Plus className="w-4 h-4 mr-2" />
              Add Staff
            </Button>
          </DialogTrigger>

          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Add New Staff Member</DialogTitle>
            </DialogHeader>

            <form onSubmit={handleSubmit} className="space-y-4">

              <div className="grid grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label>Full Name</Label>
                  <Input
                    value={formData.full_name}
                    onChange={(e) =>
                      setFormData({ ...formData, full_name: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label>Employee Number</Label>
                  <Input
                    value={formData.employee_number}
                    onChange={(e) =>
                      setFormData({ ...formData, employee_number: e.target.value })
                    }
                    required
                  />
                </div>

              </div>

              <div className="grid grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label>Email</Label>
                  <Input
                    type="email"
                    value={formData.email}
                    onChange={(e) =>
                      setFormData({ ...formData, email: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label>Phone</Label>
                  <Input
                    value={formData.phone}
                    onChange={(e) =>
                      setFormData({ ...formData, phone: e.target.value })
                    }
                    required
                  />
                </div>

              </div>

              <div className="grid grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label>Department</Label>
                  <Input
                    value={formData.department}
                    onChange={(e) =>
                      setFormData({ ...formData, department: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label>Position</Label>
                  <Input
                    value={formData.position}
                    onChange={(e) =>
                      setFormData({ ...formData, position: e.target.value })
                    }
                    required
                  />
                </div>

              </div>

              <div className="grid grid-cols-2 gap-4">

                <div className="space-y-2">
                  <Label>Role</Label>
                  <Select
                    value={formData.role}
                    onValueChange={(value) =>
                      setFormData({ ...formData, role: value })
                    }
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>

                    <SelectContent>
                      <SelectItem value="teacher">Teacher</SelectItem>
                      <SelectItem value="finance">Finance Officer</SelectItem>
                      <SelectItem value="school_admin">School Admin</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label>Joined Date</Label>
                  <Input
                    type="date"
                    value={formData.joined_date}
                    onChange={(e) =>
                      setFormData({ ...formData, joined_date: e.target.value })
                    }
                    required
                  />
                </div>

              </div>

              <div className="space-y-2">
                <Label>Password</Label>
                <Input
                  type="password"
                  value={formData.password}
                  onChange={(e) =>
                    setFormData({ ...formData, password: e.target.value })
                  }
                  required
                />
              </div>

              <Button type="submit" className="w-full">
                Add Staff Member
              </Button>

            </form>
          </DialogContent>
        </Dialog>

      </div>

      <Card>
        <CardHeader>
          <CardTitle>Staff Members</CardTitle>
        </CardHeader>

        <CardContent>

          <div className="overflow-auto rounded-lg border border-slate-200">

            <Table>

              <TableHeader>
                <TableRow className="bg-slate-50/50">
                  <TableHead>Employee No.</TableHead>
                  <TableHead>Name</TableHead>
                  <TableHead>Department</TableHead>
                  <TableHead>Position</TableHead>
                  <TableHead>Phone</TableHead>
                </TableRow>
              </TableHeader>

              <TableBody>

                {loading ? (
                  <TableRow>
                    <TableCell colSpan={5} className="text-center py-8">
                      Loading...
                    </TableCell>
                  </TableRow>

                ) : safeStaff.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={5} className="text-center py-8 text-slate-500">
                      No staff members found
                    </TableCell>
                  </TableRow>

                ) : (
                  safeStaff.map((member) => (
                    <TableRow key={member.id || member._id}>
                      <TableCell className="font-medium">
                        {member.employee_number}
                      </TableCell>

                      <TableCell>
                        {member.full_name || member.user?.full_name}
                      </TableCell>

                      <TableCell>{member.department}</TableCell>

                      <TableCell>{member.position}</TableCell>

                      <TableCell>
                        {member.phone || member.user?.phone}
                      </TableCell>
                    </TableRow>
                  ))
                )}

              </TableBody>

            </Table>

          </div>

        </CardContent>

      </Card>

    </div>
  );
};

export default StaffPage;
